"use client";

import { useQuery } from "@tanstack/react-query";

export default function ChatThread({ sessionId }: { sessionId: string | null }) {
  const { data: messages, isLoading } = useQuery({
    queryKey: ['chatMessages', sessionId],
    queryFn: async () => {
      // Mock data for immediate preview
      return [
        { id: 1, role: 'user', content: '급성 췌장염 최신 치료 지침과 논문 정리해줘' },
        { id: 2, role: 'assistant', blocks: [
          { type: 'textbook', title: '텍스트 / 권위 자료', content: '복통, 효소 상승, 영상 소견을 종합하여 판단. 초기 수액 치료 중요' },
          { type: 'journal', title: '최신 저널 의견', content: '최근 가이드라인은 공격적 수액보다 상태 기반 조절을 권장함.' },
          { type: 'doctor_consensus', title: '의사 집단 반응', summary: '개원가에서는 초기 이송이 가장 안전하다는 의견 우세 (좋아요 87 / 싫어요 12)' }
        ]}
      ];
    },
    enabled: true,
  });

  if (isLoading) return <div className="text-gray-400 text-sm text-center mt-10">메시지를 불러오는 중...</div>;

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      {messages?.map((msg, idx) => (
        <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
          <div className={`max-w-[80%] rounded-2xl p-4 ${msg.role === 'user' ? 'bg-blue-600 text-white' : 'bg-white shadow-sm border border-gray-100 flex flex-col gap-4 text-gray-800'}`}>
            {msg.role === 'user' ? (
              <p>{msg.content}</p>
            ) : (
              msg.blocks?.map((blk: any, bIdx: number) => (
                <div key={bIdx} className="border border-gray-200 rounded-lg p-4 bg-gray-50/50">
                  <h3 className="font-bold text-sm text-blue-800 mb-2 border-b pb-2">{blk.title}</h3>
                  <p className="text-sm leading-relaxed whitespace-pre-wrap">{blk.content || blk.summary}</p>
                </div>
              ))
            )}
          </div>
        </div>
      ))}
    </div>
  );
}